SELECT tsp.session_id, COUNT(tsp.phase_id) AS total_phases
FROM therapy_sessions_phases tsp
GROUP BY tsp.session_id;

SELECT COUNT(*)
FROM therapy_sessions
WHERE session_type = 'post-treatment';

SELECT P.first_name, P.last_name
FROM participants P
JOIN therapy_sessions_participants TSP ON P.participant_id = TSP.participant_id;

SELECT session_id, COUNT(DISTINCT session_date) AS session_dates_count
FROM therapy_sessions
GROUP BY session_id;

SELECT therapist_id, COUNT(*) AS total_sessions
FROM therapy_sessions
GROUP BY therapist_id;

SELECT p.first_name, p.last_name
FROM participants p
INNER JOIN therapy_sessions_participants tsp ON p.participant_id = tsp.participant_id;

SELECT session_id, session_date
FROM therapy_sessions
WHERE session_date = (
    SELECT MIN(session_date)
    FROM therapy_sessions
);
